// Input Validation
const body = $input.first().json.body;

if (!body || !body.message) {
  throw new Error('Missing required field: message');
}

if (typeof body.message !== 'string' || body.message.trim().length === 0) {
  throw new Error('Message must be a non-empty string');
}

if (body.message.length > 4000) {
  throw new Error('Message too long (max 4000 characters)');
}

return [{
  json: {
    message: body.message.trim(),
    userId: body.userId || 'anonymous',
    threadId: body.threadId || `thread-${Date.now()}`,
    timestamp: new Date().toISOString()
  }
}];

// Fetch memory from Redis (simulated)
// In production, use the Redis node or HTTP call to your backend
const threadId = $input.first().json.threadId;

// Pass through with empty memory if Redis unavailable
return [{
  json: {
    ...$input.first().json,
    conversationHistory: [],
    memoryFetched: true
  }
}];

// Parse AI response and determine if tool call is needed
const aiResponse = $input.first().json;
let parsed;

try {
  // Try to parse as JSON
  const content = aiResponse.message?.content || aiResponse.text || '';
  parsed = JSON.parse(content);
} catch (e) {
  // If not valid JSON, wrap it
  parsed = {
    response: aiResponse.message?.content || aiResponse.text || 'I could not process your request.',
    action: null,
    metadata: { intent: 'general', confidence: 0.5 }
  };
}

return [{
  json: {
    ...parsed,
    requiresToolCall: parsed.action !== null && parsed.action !== undefined,
    originalInput: $input.first().json
  }
}];

// Analyze resume tool
const params = $input.first().json.action?.params || {};
const resumeData = params.resumeData || {};

// Scoring logic
const sections = {};
let suggestions = [];

if (resumeData.summary) {
  const words = resumeData.summary.split(' ').length;
  sections.summary = { score: words >= 20 ? 85 : 50, feedback: words >= 20 ? 'Good summary' : 'Summary too short' };
} else {
  sections.summary = { score: 0, feedback: 'Missing summary' };
  suggestions.push('Add a professional summary');
}

if (resumeData.experience?.length > 0) {
  sections.experience = { score: 75, feedback: `${resumeData.experience.length} positions listed` };
} else {
  sections.experience = { score: 0, feedback: 'No experience listed' };
  suggestions.push('Add work experience');
}

if (resumeData.skills?.length >= 6) {
  sections.skills = { score: 85, feedback: 'Good skill variety' };
} else {
  sections.skills = { score: 50, feedback: 'Add more skills' };
}

const scores = Object.values(sections).map(s => s.score);
const overall = Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);

return [{ json: { success: true, data: { overallScore: overall, sections, suggestions } } }];

// Improve resume tool
const params = $input.first().json.action?.params || {};
const section = params.section || 'general';

const improvements = {
  summary: [
    'Start with years of experience and primary expertise',
    'Include 2-3 key achievements',
    'Keep it 2-4 sentences'
  ],
  experience: [
    'Use action verbs (Led, Developed, Implemented)',
    'Quantify achievements with numbers',
    'Focus on impact, not responsibilities'
  ],
  skills: [
    'Group skills by category',
    'List most relevant first',
    'Include both technical and soft skills'
  ]
};

return [{ json: { success: true, data: { section, suggestions: improvements[section] || improvements.summary } } }];

// Format the final response
const data = $input.first().json;

let response;
if (data.response) {
  // Direct response (no tool call)
  response = data.response;
} else if (data.success !== undefined) {
  // Tool result — pass back through AI for natural language formatting
  response = JSON.stringify(data);
} else {
  response = 'I processed your request. Is there anything else I can help with?';
}

return [{
  json: {
    success: true,
    data: {
      response: response,
      timestamp: new Date().toISOString()
    }
  }
}];

// Log the request and response
const data = $input.first().json;
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'agent_response',
  success: data.success,
  responseLength: data.data?.response?.length || 0
}));

return [$input.first()];

// Error handler
const error = $input.first().json;
console.error('Workflow error:', JSON.stringify(error));

return [{
  json: {
    success: false,
    error: 'An error occurred processing your request',
    timestamp: new Date().toISOString()
  }
}];
